UPDATE CARD_VERSIONS SET version_status = 'ARCHIVED' WHERE card_id IN
#{id}
AND version_status = 'PUBLISHED'

mapper.select:
SELECT * FROM CARD_IMAGES
WHERE  card_id = #{cardId}
ORDER  BY sort_order ASC NULLS LAST

mapper.update:
UPDATE CARD_IMAGES
SET    image_type    = #{imageType},
       image_url     = #{imageUrl},
       original_name = #{originalName, jdbcType=VARCHAR},
       sort_order    = #{sortOrder,    jdbcType=NUMERIC}
WHERE  image_id = #{imageId}
